
#!/usr/bin/env bash
set -Eeuo pipefail

ROOT_REPO="${ROUTEIQ_ROOT_REPO:-/workspaces/omniedge-routeiq}"
WORKTREE="${ROUTEIQ_WORKTREE:-/tmp/routeiq-v171}"
BASE_BRANCH="track1-v17-accuracy-first"
BRANCH="track1-v171-runtime-safe"
AGENT_DIR="track1-v171-agent"
WORKFLOW_FILE=".github/workflows/publish-track1-v171.yml"
WORKFLOW_NAME="Publish RouteIQ v1.7.1 Runtime Safe"
LOCAL_IMAGE="routeiq-v171-runtime-safe:test"

say() { printf '\n==> %s\n' "$*"; }
die() { printf '\nERROR: %s\n' "$*" >&2; exit 1; }
cleanup() {
  set +e
  if [[ -n "${MOCK_NAME:-}" ]]; then docker rm -f "$MOCK_NAME" >/dev/null 2>&1; fi
  if [[ -n "${NETWORK_NAME:-}" ]]; then docker network rm "$NETWORK_NAME" >/dev/null 2>&1; fi
}
trap cleanup EXIT
trap 'printf "\nFAILED at line %s. The portal and scored champion were not changed.\n" "$LINENO" >&2' ERR

for command in git gh docker python3 base64 sudo timeout; do
  command -v "$command" >/dev/null || die "$command is required"
done
[[ -d "$ROOT_REPO/.git" ]] || die "repository not found: $ROOT_REPO"

say "Preparing an isolated writable v1.7.1 worktree"
cd "$ROOT_REPO"
git worktree prune
if [[ -e "$WORKTREE" ]]; then
  git worktree remove --force "$WORKTREE" >/dev/null 2>&1 || sudo rm -rf "$WORKTREE"
fi
if git show-ref --verify --quiet "refs/heads/$BRANCH"; then
  git worktree add "$WORKTREE" "$BRANCH"
else
  git worktree add -b "$BRANCH" "$WORKTREE" "$BASE_BRANCH"
fi
cd "$WORKTREE"
sudo chown -R "$(id -u):$(id -g)" "$WORKTREE"
chmod -R u+rwX "$WORKTREE"
mkdir -p /workspaces/.routeiq-private
chmod 700 /workspaces/.routeiq-private

say "Installing the tested v1.7.1 runtime-safe source"
rm -rf "$AGENT_DIR"
rm -f "$WORKFLOW_FILE"
mkdir -p .github/workflows
BUNDLE="$(mktemp)"
base64 -d > "$BUNDLE" <<'ROUTEIQ_V171_BUNDLE'

ROUTEIQ_V171_BUNDLE
tar -xzf "$BUNDLE" -C "$WORKTREE"
rm -f "$BUNDLE"
sudo chown -R "$(id -u):$(id -g)" "$AGENT_DIR" .github
chmod -R u+rwX "$AGENT_DIR" .github

say "Running syntax and 32 unit/runtime-safety tests"
(
  cd "$AGENT_DIR"
  python3 -m py_compile agent.py local/*.py
  python3 -m unittest discover -s tests -v
)

say "Building the tiny linux/amd64 candidate"
docker build --progress=plain -t "$LOCAL_IMAGE" "$AGENT_DIR"
ARCH="$(docker image inspect --format '{{.Architecture}}' "$LOCAL_IMAGE")"
SIZE="$(docker image inspect --format '{{.Size}}' "$LOCAL_IMAGE")"
[[ "$ARCH" == "amd64" ]] || die "candidate architecture is $ARCH"
(( SIZE < 1000000000 )) || die "candidate unexpectedly exceeds 1 GB"
printf 'LOCAL_IMAGE_BYTES=%s\n' "$SIZE"

say "Running deterministic no-network smoke test"
SMOKE_ROOT="$(mktemp -d)"
mkdir -p "$SMOKE_ROOT/input" "$SMOKE_ROOT/output"
chmod 777 "$SMOKE_ROOT/output"
cat > "$SMOKE_ROOT/input/tasks.json" <<'JSON'
[
  {"task_id":"math","task_type":"mathematical reasoning","prompt":"Calculate 18 * 7. Return only the number."},
  {"task_id":"sentiment","task_type":"sentiment classification","prompt":"Classify as positive, negative, or neutral: The deployment completed successfully."}
]
JSON
docker run --rm --network none --cpus=2 --memory=4g   -v "$SMOKE_ROOT/input:/input:ro"   -v "$SMOKE_ROOT/output:/output"   "$LOCAL_IMAGE"
python3 - "$SMOKE_ROOT/output/results.json" <<'PY'
import json,sys
actual=json.load(open(sys.argv[1],encoding='utf-8'))
expected=[{'task_id':'math','answer':'126'},{'task_id':'sentiment','answer':'positive'}]
if actual != expected:
    raise SystemExit(f'deterministic smoke mismatch: {actual!r}')
print('DETERMINISTIC_SMOKE=PASS')
PY

say "Running end-to-end mocked Fireworks test, including structured-output rejection fallback"
NETWORK_NAME="routeiq-v171-$RANDOM-$RANDOM"
MOCK_NAME="routeiq-mock-$RANDOM-$RANDOM"
docker network create "$NETWORK_NAME" >/dev/null
MOCK_ROOT="$(mktemp -d)"
cat > "$MOCK_ROOT/server.py" <<'PY'
import json
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer

class Handler(BaseHTTPRequestHandler):
    def log_message(self, fmt, *args):
        pass
    def do_POST(self):
        length=int(self.headers.get('Content-Length','0'))
        payload=json.loads(self.rfile.read(length).decode('utf-8'))
        if 'response_format' in payload:
            body=json.dumps({'error':'mock rejects schema once'}).encode()
            self.send_response(400)
        else:
            content=json.dumps({'r':[{'i':0,'a':'Tokyo'},{'i':1,'a':'def add(a, b):\n    return a + b'}]})
            body=json.dumps({'choices':[{'message':{'content':content}}]}).encode()
            self.send_response(200)
        self.send_header('Content-Type','application/json')
        self.send_header('Content-Length',str(len(body)))
        self.end_headers()
        self.wfile.write(body)

ThreadingHTTPServer(('0.0.0.0',8080),Handler).serve_forever()
PY
docker run -d --rm --name "$MOCK_NAME" --network "$NETWORK_NAME"   --entrypoint python3   -v "$MOCK_ROOT:/mock:ro"   "$LOCAL_IMAGE" /mock/server.py >/dev/null
sleep 1
REMOTE_ROOT="$(mktemp -d)"
mkdir -p "$REMOTE_ROOT/input" "$REMOTE_ROOT/output"
chmod 777 "$REMOTE_ROOT/output"
cat > "$REMOTE_ROOT/input/tasks.json" <<'JSON'
[
  {"task_id":"math","task_type":"mathematical reasoning","prompt":"Calculate 8 * 7. Return only the number."},
  {"task_id":"fact","task_type":"factual knowledge","prompt":"What is the capital of Japan?"},
  {"task_id":"code","task_type":"code generation","prompt":"Write Python code defining add(a, b) that returns their sum."}
]
JSON
docker run --rm --network "$NETWORK_NAME" --cpus=2 --memory=4g   -e FIREWORKS_API_KEY=mock   -e FIREWORKS_BASE_URL="http://$MOCK_NAME:8080/v1"   -e 'ALLOWED_MODELS=["minimax-m3"]'   -v "$REMOTE_ROOT/input:/input:ro"   -v "$REMOTE_ROOT/output:/output"   "$LOCAL_IMAGE"
python3 - "$REMOTE_ROOT/output/results.json" <<'PY'
import ast,json,sys
actual=json.load(open(sys.argv[1],encoding='utf-8'))
by_id={str(x['task_id']):x['answer'] for x in actual}
assert by_id['math']=='56',actual
assert by_id['fact']=='Tokyo',actual
ast.parse(by_id['code'])
assert 'return a + b' in by_id['code'],actual
print('MOCKED_REMOTE_E2E=PASS')
PY

docker rm -f "$MOCK_NAME" >/dev/null
MOCK_NAME=""
docker network rm "$NETWORK_NAME" >/dev/null
NETWORK_NAME=""

say "Running forced remote-outage test to prove it exits cleanly instead of RUNTIME_ERROR"
OUTAGE_ROOT="$(mktemp -d)"
mkdir -p "$OUTAGE_ROOT/input" "$OUTAGE_ROOT/output"
chmod 777 "$OUTAGE_ROOT/output"
cat > "$OUTAGE_ROOT/input/tasks.json" <<'JSON'
[{"task_id":"fact","task_type":"factual knowledge","prompt":"What is the capital of Japan?"}]
JSON
set +e
timeout 30 docker run --rm --cpus=2 --memory=4g   -e FIREWORKS_API_KEY=mock   -e FIREWORKS_BASE_URL='http://127.0.0.1:1/v1'   -e 'ALLOWED_MODELS=["minimax-m3"]'   -e ROUTEIQ_REQUEST_TIMEOUT=1   -v "$OUTAGE_ROOT/input:/input:ro"   -v "$OUTAGE_ROOT/output:/output"   "$LOCAL_IMAGE"
OUTAGE_STATUS="$?"
set -e
[[ "$OUTAGE_STATUS" -eq 0 ]] || die "outage test exited nonzero: $OUTAGE_STATUS"
python3 - "$OUTAGE_ROOT/output/results.json" <<'PY'
import json,sys
actual=json.load(open(sys.argv[1],encoding='utf-8'))
assert actual == [{'task_id':'fact','answer':''}],actual
print('RUNTIME_FAIL_CLOSED=PASS')
PY

say "Committing the isolated v1.7.1 candidate"
find "$AGENT_DIR" -type d -name __pycache__ -prune -exec rm -rf {} +
find "$AGENT_DIR" -type f -name '*.pyc' -delete
git add "$AGENT_DIR" "$WORKFLOW_FILE"
if ! git diff --cached --quiet; then
  git commit -m "fix(track1): harden v1.7 remote runtime path"
fi
COMMIT="$(git rev-parse HEAD)"

say "Pushing the experimental branch"
git push -u origin "$BRANCH"

say "Waiting for GitHub Actions publication"
RUN_ID=""
for _ in $(seq 1 36); do
  RUN_ID="$(gh run list --workflow "$WORKFLOW_NAME" --branch "$BRANCH" --limit 5     --json databaseId,headSha --jq ".[] | select(.headSha == \\"$COMMIT\\") | .databaseId" 2>/dev/null | head -n1 || true)"
  [[ -n "$RUN_ID" ]] && break
  sleep 5
done
[[ -n "$RUN_ID" ]] || die "workflow did not appear; inspect GitHub Actions"
RUN_URL="$(gh run view "$RUN_ID" --json url --jq '.url')"
printf 'Workflow: %s\n' "$RUN_URL"
gh run watch "$RUN_ID" --exit-status

OWNER="$(gh repo view --json owner --jq '.owner.login')"
[[ -n "$OWNER" ]] || die "could not determine repository owner"
IMAGE="ghcr.io/${OWNER,,}/omniedge-routeiq-track1:c-v171-$COMMIT"

say "Verifying the published public manifest"
VERIFIED=0
for _ in $(seq 1 18); do
  if docker manifest inspect "$IMAGE" >/dev/null 2>&1; then VERIFIED=1; break; fi
  sleep 5
done
[[ "$VERIFIED" == "1" ]] || die "published manifest is not publicly readable"

PRIVATE_FILE="/workspaces/.routeiq-private/v171-candidate.txt"
{
  printf 'PRIVATE — DO NOT POST IN DISCORD, README, OR SCREENSHOTS\n'
  printf 'image=%s\n' "$IMAGE"
  printf 'commit=%s\n' "$COMMIT"
  printf 'workflow=%s\n' "$RUN_URL"
  printf 'architecture=v1.7.1 compact accuracy-first runtime-safe hybrid\n'
  printf 'tests=32 unit/runtime tests + deterministic Docker + mocked Fireworks E2E + forced outage\n'
  printf 'portal_changed=no\n'
} > "$PRIVATE_FILE"
chmod 600 "$PRIVATE_FILE"
cp "$PRIVATE_FILE" /tmp/routeiq-v171-private-candidate.txt
chmod 600 /tmp/routeiq-v171-private-candidate.txt

say "v1.7.1 published successfully"
printf 'Private candidate record: %s\n' "$PRIVATE_FILE"
printf 'The portal and scored champion were not changed.\n'
printf 'Do not submit until this final output is reviewed.\n'
